var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>여기는 E-1-5. 최초 급성침식파 발생 후 침식 수준 현상 유지 중.</color>","JPN":"<color=#ffd34c>こちら、E-1-5。最初の急性侵食波の発生後、侵食レベルは現状を維持中。</color>","ENG":"<color=#ffd34c>E-1-5 reporting, over. Corruption level stabilized after initial acute Corruption ray.</color>","TWN":"<color=#ffd34c>這裡是E-1-5，從第一個急性侵蝕波發生後，侵蝕現象一直在持續當中。</color>"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>도시구역 다수에서 동시다발적인 침식체 출몰을 확인.</color>","JPN":"<color=#ffd34c>多数の都市区域で同時多発的な侵食体の出没を確認。</color>","ENG":"<color=#ffd34c>C.O.s spotted in multiple locations around the city.</color>","TWN":"<color=#ffd34c>目前多個城市皆同時有侵蝕體出現，</color>"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>초동대응팀만으론 안전확보가 어렵다. 지원을 요청한다.</color>","JPN":"<color=#ffd34c>初動対応チームだけでは安全を確保することは難しい。支援を要請する。</color>","ENG":"<color=#ffd34c>We’re going to need more firepower. Requesting reinforcement, over.</color>","TWN":"<color=#ffd34c>光靠現有的人力難以確保安全，請求支援。</color>"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"여기는 HQ. 도시관리국 지침에 따라, 현 사태를 비상조치 레벨 3로 격상.","JPN":"こちら、HQ。都市管理局の指針により、当事態を非常措置レベル3に格上げ。","ENG":"This is HQ. Following the City Management guidelines, we hereby announce the current disaster’s severity as emergency level 3.","TWN":"這裡是HQ，根據城市管理局指示，升級為3級警戒。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"관할 외 태스크포스들에게도 지원 요청을 승인받았습니다.","JPN":"管轄外のタスクフォースに送った支援要請も承認されています。","ENG":"We have obtained permission from all TASKFORCE out of our jurisdiction.","TWN":"轄區外的特遣勢力也已同意加入支援。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"QUARANTINE_NPC_NULL_NULL","text":{"KOREA":"또 도시 한복판에서 급성 침식이라니. 이래선 내 집에서도 발 뻗고 못 자겠네.","JPN":"また都市の真ん中で急性侵食だなんて。これじゃあ自分の家でも安心して眠れないぞ。","ENG":"Another acute Corruption in the heart of the city? I guess I won’t even feel safe at my own home.","TWN":"市中心竟然又發生急性侵蝕，根本就沒時間可以休息嘛。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"QUARANTINE_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DEFENDER_NPC_NANAHARA2_NULL","text":{"KOREA":"한 달 사이에만 벌써 세 번째네요. 안전에 대한 시민들 여론도 최악이고요.","JPN":"今月すでに3回目ですからね。安全についての市民の世論も最悪ですし。","ENG":"It’s already the third time this month. Our reputation to the public hit rock bottom.","TWN":"這已經是這個月的第三次，現在都民怨沸騰了。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"QUARANTINE_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEFENDER_NPC_NANAHARA2_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"QUARANTINE_NPC_NULL_NULL","text":{"KOREA":"어쩌겠어. 우린 신이 아니라 돈 받으며 최전선에서 궂은 일하는 사람들이라고.","JPN":"どうしろってんだ。俺たちは神様じゃなくて、お金もらって最前線できつい仕事をしてる普通の人なんだぜ。","ENG":"Well, there’s nothing we can do. We are just frontline workers, not god.","TWN":"能怎麼辦？我們又不是神，我們只是拿錢辦事而已，而且還是屎缺。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"QUARANTINE_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEFENDER_NPC_NANAHARA2_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"QUARANTINE_NPC_NULL_NULL","text":{"KOREA":"음……? 방금 저쪽에서 무슨 소리 들리지 않았어?","JPN":"うん……？　さっきあそこから何か聞こえなかったか？","ENG":"Hmm...? Didn’t you hear something over there?","TWN":"嗯……？那邊好像有什麼聲音，你有聽到嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"QUARANTINE_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEFENDER_NPC_NANAHARA2_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"DEFENDER_NPC_NANAHARA2_NULL","text":{"KOREA":"조심하세요. 그쪽 골목은 아직 안전한지 모르는……","JPN":"気をつけてくださいよ。そっちの裏道はまだ安全かどうかわからな……","ENG":"Be careful. We haven’t checked the alleyway over–","TWN":"小心點，那條巷子不知道安不安全……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEFENDER_NPC_NANAHARA2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"우와앗!!!","JPN":"うわっ！！！","ENG":"Whoa!!!","TWN":"啊啊啊！！！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEFENDER_NPC_NANAHARA2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DEFENDER_NPC_NANAHARA2_NULL","text":{"KOREA":"이런!","JPN":"しまった！","ENG":"Oh, no!","TWN":"該死！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEFENDER_NPC_NANAHARA2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DEFENDER_NPC_NANAHARA2_NULL","text":{"KOREA":"침식체입니까?!","JPN":"侵食体ですか！？","ENG":"Is it a C.O.?!","TWN":"是侵蝕體嗎？！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"QUARANTINE_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEFENDER_NPC_NANAHARA2_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"QUARANTINE_NPC_NULL_NULL","text":{"KOREA":"그…… 그렇긴 한데…….","JPN":"そ……そうなんだが……","ENG":"I... I think so...?","TWN":"是……沒錯……"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"QUARANTINE_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEFENDER_NPC_NANAHARA2_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"QUARANTINE_NPC_NULL_NULL","text":{"KOREA":"누가 이미 다녀간 것 같은데?","JPN":"すでに誰かが来てたみたいだぞ？","ENG":"But it looks like someone’s already taken care of them.","TWN":"但好像有人來過咧？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"QUARANTINE_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEFENDER_NPC_NANAHARA2_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"DEFENDER_NPC_NANAHARA2_NULL","text":{"KOREA":"이럴 수가. 누가 이렇게 많은 침식체들을 전부 해치운 거죠?","JPN":"そんな。誰がこの数の侵食体を全部片付けたんでしょうか？","ENG":"Unbelievable. How could anyone take down this many C.O.s all at once?","TWN":"怎麼可能，誰有辦法處理掉這麼多侵蝕體？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"QUARANTINE_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEFENDER_NPC_NANAHARA2_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_QM","text":{"KOREA":"에고, 삭신이야. 일단은 이 녀석이 마지막인가?","JPN":"くぅ、体の節々が痛むのう。一応こやつが最後か？","ENG":"Ouch, my back. Well, this one should be the last.","TWN":"哎唷喂呀，我的骨頭都要散啦，這是最後一隻嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SHOP_NPC_NULL_NULL","text":{"KOREA":"다, 당신……","JPN":"あ、あんた……","ENG":"Y-you...","TWN":"你，你……"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_QM","text":{"KOREA":"……응?","JPN":"……む？","ENG":"...Hmm?","TWN":"……嗯？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_QM","text":{"KOREA":"오, 주인장. 아직 살아있어서 다행이구만.","JPN":"おお、ご主人。無事でなによりだ。","ENG":"Oh, you're here. I’m glad you’re still alive!","TWN":"喔，老闆，幸好你還活著。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SHOP_NPC_NULL_NULL","text":{"KOREA":"혼자 그 많은 침식체와 싸우고도 멀쩡하다니…… 대체 뭐하는 분이시죠?","JPN":"一人であの数の侵食体と戦って何ともないなんて……いったい何をしている方なんですか？","ENG":"You don’t look even the slightest bit tired, after fighting all those C.O.s... Who are you?","TWN":"竟然自己一個人對付那麼多侵蝕體還沒事……敢問您是何方神聖？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_QM","text":{"KOREA":"으음, 글쎄. 옛날처럼 설명할 필요는 없을 테니 나를 이젠 뭐라 소개한다?","JPN":"うーむ、そうだな。昔のような説明はいらないとして、わしを何と紹介したものか。","ENG":"Erm, well... How should I put this? I don’t have my former title anymore.","TWN":"嗯，這個嘛，應該不需要像以前那樣解釋，那該怎麼介紹我呢？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_QM","text":{"KOREA":"아.","JPN":"あ。","ENG":"Oh.","TWN":"有啦，"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_QM","text":{"KOREA":"관리국 직원…… 이라고 하면 되나?","JPN":"管理局の職員……でどうかのう？","ENG":"I work for the Administration... kind of.","TWN":"就說是……管理局員工吧？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":null,"text":{"KOREA":"도시관리국에서 오신 분이라면, 오피셜 서포트 소속의 카운터이신가요?","JPN":"都市管理局から来た方なら、オフィシャルサポート所属のカウンターなんですか？","ENG":"If you’re from the City Management, are you a part of the Official Support?","TWN":"您是城市管理局派來的嗎？那是隸屬於官方支援的制裁者嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_QM","text":{"KOREA":"음? 그런 소속은 아니다만. 너희는 누구냐?","JPN":"む？　そんな所属ではないぞ。お主らは誰じゃ？","ENG":"Mm? No, not really. But who are you?","TWN":"嗯？我才不隸屬於誰啦，倒是你們是誰？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"DEFENDER_NPC_NANAHARA2_NULL","text":{"KOREA":"아, 저희는 도시관리국의 요청으로 지원을 오게 된 태스크포스입니다.","JPN":"あ、私たちは都市管理局の支援要請により出動したタスクフォースです。","ENG":"Oh, we are the reinforcement TASKFORCE requested by the City Management.","TWN":"喔，我們是受到城市管理局委託前來支援的特遣勢力。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DEFENDER_NPC_NANAHARA2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"DEFENDER_NPC_NANAHARA2_NULL","text":{"KOREA":"믿기진 않지만…… 정황상 저희가 맡은 정화구역을 아가씨가 대신 정리한 것 같네요.","JPN":"信じられませんが……状況を見ると私たちが担当している浄化区域をお嬢さんが代わりに片付いてくれたようですね。","ENG":"I find it hard to believe so... but it looks like you took care of our designated purification site.","TWN":"真沒想到……這裡原本是我們負責的淨化區域，只是你好像都替我們處理完了。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DEFENDER_NPC_NANAHARA2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_QM","text":{"KOREA":"그래? 젊은 것들이 뛰어다니느라 고생이 많구나.","JPN":"そうか？　若いのにお仕事ご苦労さん。","ENG":"Did I? Must be tough for youngsters like you to run around here and there.","TWN":"是嗎？年輕人這樣奔波很辛苦呢。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DEFENDER_NPC_NANAHARA2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_LAUGH"}}}},{"id":"L47_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_QM","text":{"KOREA":"그렇지. 네놈들, 나나하라 가문연합이라고 들어봤나?","JPN":"そうだ。お主たち、七原家連合という名を聞いたことはあるか？","ENG":"Oh, that's right. You two, ever heard of the Nanahara Family Alliance?","TWN":"對了，你們有聽說過七原家族聯盟嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DEFENDER_NPC_NANAHARA2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"DEFENDER_NPC_NANAHARA2_NULL","text":{"KOREA":"나나하라…… 말입니까? 글쎄요. 그런 이름의 태스크포스는 들어본 적이 없는데.","JPN":"七原……ですか？　さあ。そんな名前のタスクフォースは聞いたことがないですが。","ENG":"Nanahara, you say...? I’m not sure. Never heard of a TASKFORCE named like that.","TWN":"七原……嗎？沒聽過欸？特遣勢力中好像沒這號人物。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DEFENDER_NPC_NANAHARA2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"QUARANTINE_NPC_NULL_NULL","text":{"KOREA":"음……? 아, 그러고보니…….","JPN":"うん……？　あ、そういえば……","ENG":"Hmm...? Oh, Come to think of it...","TWN":"嗯……？話說回來……"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUARANTINE_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"QUARANTINE_NPC_NULL_NULL","text":{"KOREA":"최근에 침식사태 때마다 태스크포스들을 무보수로 돕는 소속 없는 카운터들이 있었죠.","JPN":"最近、侵食事態が起きるたびに無報酬でタスクフォースを手伝ってくれる所属のないカウンターたちがいるんですが。","ENG":"There were unregistered Counters helping the TASKFORCE for free in the recent Corruption disasters.","TWN":"最近每次發生侵蝕事件時，都會有體制外的制裁者無酬協助特遣勢力。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUARANTINE_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"QUARANTINE_NPC_NULL_NULL","text":{"KOREA":"그중 한 명이 나나하라라는 이름을 쓰는 칼잡이였던 걸로 기억합니다.","JPN":"その中の一人が七原って名の剣士だったと思います。","ENG":"I remember one of them was a blade wielder who went by the name of Nanahara.","TWN":"我記得其中一個人的刀上刻的就是七原。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUARANTINE_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DEFENDER_NPC_NANAHARA2_NULL","text":{"KOREA":"아, 맞아요. 제가 데이마인에 근무할 적에도 검을 쓰는 카운터를 봤지만, 그 검술은 수준이 다르다는 느낌이었죠.","JPN":"そうそう。私がデイマインで働いてた頃も剣を使うカウンターは見ましたが、その人の剣術はレベルが違う感じがしました。","ENG":"Oh, right. I saw a Counter who used a sword from back at my days at Daymine, but she was different.","TWN":"喔，對啊，我在戴瑪因值勤時也遇過會用刀的制裁者，但那個人的劍法水準完全是不同層次。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DEFENDER_NPC_NANAHARA2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_QM","text":{"KOREA":"오, 그럼 그 친구가 지금 어디에 있는지도 알고 있나?","JPN":"おお、ならばその者が今どこにいるかも知っておるか？","ENG":"Oh, do you also happen to know where she is in now?","TWN":"喔，那你知道那個人現在在哪嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DEFENDER_NPC_NANAHARA2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"DEFENDER_NPC_NANAHARA2_NULL","text":{"KOREA":"이번 침식사태의 범위가 워낙 넓어야 말이죠. 그 분들은 아마 지금쯤 다른 어딘가에서 침식사태를 막고 계실 겁니다.","JPN":"今度の侵食事態は範囲が広すぎてですね。あの方たちは多分今頃違うどこかで侵食事態を止めてるはずだと思いますよ。","ENG":"The current Corruption disaster is huge. She will probably be out there somewhere, trying to stop the Corruption from worsening.","TWN":"這次侵蝕事件的範圍很廣，他們現在應該也正在某個地方處理侵蝕事件吧？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DEFENDER_NPC_NANAHARA2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"QUARANTINE_NPC_NULL_NULL","text":{"KOREA":"뭐, 그건 그렇고. 잠시 신원 조회에 협조 좀 해주시겠습니까?","JPN":"まあ、それはそうとして。ちょっと身元調査にご協力をお願いします。","ENG":"Well, that aside... I’m afraid you will have to show us your ID card.","TWN":"嗯，不過還是要照規矩來，麻煩你配合一下身分調查。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUARANTINE_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"QUARANTINE_NPC_NULL_NULL","text":{"KOREA":"소속이 다른 카운터 분 공로를 상부가 저희 실적으로 오해하면 곤란하거든……","JPN":"所属の異なるカウンターの手柄を、上層部が私たちの実績と誤解するといけません……","ENG":"Things will get messy if the higher-ups mistake your credit for–","TWN":"萬一上頭的人把其他制裁者的功勞當成是我們的，那可就不……"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUARANTINE_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"QUARANTINE_NPC_NULL_NULL","text":{"KOREA":"……요. 어디로 갔지?","JPN":"……ので。どこに行ったんだ？","ENG":"...Ours. Where did she go?","TWN":"……好囉，人呢？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUARANTINE_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DEFENDER_NPC_NANAHARA2_NULL","text":{"KOREA":"순식간에 사라졌네요.","JPN":"あっという間に消えちゃいましたね。","ENG":"She’s gone.","TWN":"瞬間消失欸？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"QUARANTINE_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEFENDER_NPC_NANAHARA2_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"DEFENDER_NPC_NANAHARA2_NULL","text":{"KOREA":"도마뱀꼬리가 달린 여성이 혼자 침식체를 다 쓸어버렸다고 보고하면 될까요?","JPN":"トカゲの尻尾がついている女性が一人で侵食体を全滅させたって報告すればいいんでしょうか。","ENG":"Should we just report that a lizard-tailed woman took down all of the C.O.s?","TWN":"我們就回報上頭的人說，這些侵蝕體都是一個有蜥蜴尾巴的女生處理掉的嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"QUARANTINE_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEFENDER_NPC_NANAHARA2_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"QUARANTINE_NPC_NULL_NULL","text":{"KOREA":"안 믿어주면 그냥 우리가 처리했다고 하지 뭐.","JPN":"まあ、信じてくれなかったら俺たちが片付けたってことするか。","ENG":"If they don’t believe us, let’s just tell them we did it.","TWN":"上面的人不信的話，就說是我們做的吧。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"QUARANTINE_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEFENDER_NPC_NANAHARA2_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};